import requests
import json
import sys
from typing import List, Dict, Optional
from requests.auth import HTTPBasicAuth


class RabbitMQConfigurator:
    def __init__(self, host: str = "localhost", port: int = 15672, 
                 username: str = "guest", password: str = "guest"):
        self.base_url = f"http://{host}:{port}/api"
        self.auth = HTTPBasicAuth(username, password)
        self.session = requests.Session()
        self.session.auth = self.auth
        
    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> requests.Response:
        url = f"{self.base_url}/{endpoint}"
        headers = {"Content-Type": "application/json"}
        
        try:
            if method == "GET":
                response = self.session.get(url, headers=headers)
            elif method == "PUT":
                response = self.session.put(url, headers=headers, 
                                           data=json.dumps(data) if data else None)
            elif method == "DELETE":
                response = self.session.delete(url, headers=headers)
            elif method == "POST":
                response = self.session.post(url, headers=headers, 
                                            data=json.dumps(data) if data else None)
            
            return response
        except requests.exceptions.RequestException as e:
            print(f"Error making request to {url}: {e}")
            sys.exit(1)
    
    def create_vhost(self, vhost_name: str) -> bool:
        print(f"Creating vhost: {vhost_name}")
        response = self._make_request("PUT", f"vhosts/{vhost_name}")
        
        if response.status_code in [201, 204]:
            print(f"✓ Vhost '{vhost_name}' created successfully")
            return True
        else:
            print(f"✗ Failed to create vhost '{vhost_name}': {response.status_code} - {response.text}")
            return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        print(f"Deleting vhost: {vhost_name}")
        response = self._make_request("DELETE", f"vhosts/{vhost_name}")
        
        if response.status_code == 204:
            print(f"✓ Vhost '{vhost_name}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete vhost '{vhost_name}': {response.status_code}")
            return False
    
    def list_vhosts(self) -> List[Dict]:
        response = self._make_request("GET", "vhosts")
        
        if response.status_code == 200:
            vhosts = response.json()
            print(f"\nExisting vhosts ({len(vhosts)}):")
            for vhost in vhosts:
                print(f"  - {vhost['name']}")
            return vhosts
        else:
            print(f"✗ Failed to list vhosts: {response.status_code}")
            return []
    
    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        print(f"Creating user: {username}")
        data = {
            "password": password,
            "tags": tags
        }
        response = self._make_request("PUT", f"users/{username}", data)
        
        if response.status_code in [201, 204]:
            print(f"✓ User '{username}' created successfully")
            return True
        else:
            print(f"✗ Failed to create user '{username}': {response.status_code} - {response.text}")
            return False
    
    def delete_user(self, username: str) -> bool:
        print(f"Deleting user: {username}")
        response = self._make_request("DELETE", f"users/{username}")
        
        if response.status_code == 204:
            print(f"✓ User '{username}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete user '{username}': {response.status_code}")
            return False
    
    def list_users(self) -> List[Dict]:
        response = self._make_request("GET", "users")
        
        if response.status_code == 200:
            users = response.json()
            print(f"\nExisting users ({len(users)}):")
            for user in users:
                print(f"  - {user['name']} (tags: {user.get('tags', 'none')})")
            return users
        else:
            print(f"✗ Failed to list users: {response.status_code}")
            return []
    
    def set_permissions(self, vhost: str, username: str, 
                       configure: str = ".*", write: str = ".*", read: str = ".*") -> bool:
        print(f"Setting permissions for user '{username}' on vhost '{vhost}'")
        data = {
            "configure": configure,
            "write": write,
            "read": read
        }
        response = self._make_request("PUT", f"permissions/{vhost}/{username}", data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Permissions set for '{username}' on '{vhost}' (configure: {configure}, write: {write}, read: {read})")
            return True
        else:
            print(f"✗ Failed to set permissions: {response.status_code} - {response.text}")
            return False
    
    def get_permissions(self, vhost: str, username: str) -> Optional[Dict]:
        response = self._make_request("GET", f"permissions/{vhost}/{username}")
        
        if response.status_code == 200:
            return response.json()
        else:
            return None
    
    def list_permissions(self, vhost: Optional[str] = None) -> List[Dict]:
        if vhost:
            endpoint = f"vhosts/{vhost}/permissions"
        else:
            endpoint = "permissions"
        
        response = self._make_request("GET", endpoint)
        
        if response.status_code == 200:
            permissions = response.json()
            print(f"\nPermissions for vhost '{vhost if vhost else 'all'}':")
            for perm in permissions:
                print(f"  - User: {perm['user']}, Vhost: {perm['vhost']}")
                print(f"    Configure: {perm['configure']}, Write: {perm['write']}, Read: {perm['read']}")
            return permissions
        else:
            print(f"✗ Failed to list permissions: {response.status_code}")
            return []
    
    def delete_permissions(self, vhost: str, username: str) -> bool:
        print(f"Deleting permissions for user '{username}' on vhost '{vhost}'")
        response = self._make_request("DELETE", f"permissions/{vhost}/{username}")
        
        if response.status_code == 204:
            print(f"✓ Permissions deleted for '{username}' on '{vhost}'")
            return True
        else:
            print(f"✗ Failed to delete permissions: {response.status_code}")
            return False
    
    def set_topic_permissions(self, vhost: str, username: str, exchange: str,
                             write: str = ".*", read: str = ".*") -> bool:
        print(f"Setting topic permissions for user '{username}' on vhost '{vhost}' for exchange '{exchange}'")
        data = {
            "exchange": exchange,
            "write": write,
            "read": read
        }
        response = self._make_request("PUT", f"topic-permissions/{vhost}/{username}", data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Topic permissions set for '{username}' on '{vhost}'")
            return True
        else:
            print(f"✗ Failed to set topic permissions: {response.status_code} - {response.text}")
            return False
    
    def setup_multi_tenant_environment(self, tenants: List[Dict]) -> None:
        print("\n" + "="*60)
        print("Setting up multi-tenant RabbitMQ environment")
        print("="*60 + "\n")
        
        for tenant in tenants:
            tenant_name = tenant.get("name")
            vhost_name = tenant.get("vhost", f"vhost_{tenant_name}")
            users = tenant.get("users", [])
            
            print(f"\n--- Configuring tenant: {tenant_name} ---")
            
            # Create vhost
            self.create_vhost(vhost_name)
            
            # Create users and set permissions
            for user in users:
                username = user.get("username")
                password = user.get("password")
                tags = user.get("tags", "")
                permissions = user.get("permissions", {})
                
                # Create user
                self.create_user(username, password, tags)
                
                # Set permissions
                configure = permissions.get("configure", ".*")
                write = permissions.get("write", ".*")
                read = permissions.get("read", ".*")
                
                self.set_permissions(vhost_name, username, configure, write, read)
            
            print(f"--- Tenant {tenant_name} configuration complete ---\n")
        
        print("\n" + "="*60)
        print("Multi-tenant environment setup complete")
        print("="*60 + "\n")


